    let n = read_int();
    let q = read_int();
    let v = vec_new();
    for _i in 0..n {
        let val = read_int();
        let _p = vec_push(v, val)
    };

    // Build prefix sum array
    // prefix[i] = sum of v[0..i-1]
    // prefix[0] = 0
    // prefix[k] = v[0] + ... + v[k-1]
    // Range sum [l, r] (inclusive) = prefix[r+1] - prefix[l]
    let prefix = vec_new();
    let _p0 = vec_push(prefix, 0);
    let mut acc = 0;
    let i = 0;
    while i < n {
        acc = acc + vec_get(v, i);
        let _p = vec_push(prefix, acc);
        i = i + 1
    };

    // Process queries
    let qi = 0;
    while qi < q {
        let l = read_int();
        let r = read_int();
        // Range sum from index l to r (inclusive)
        // Using prefix sums: sum(l..=r) = prefix[r+1] - prefix[l]
        let sum_r_plus_1 = vec_get(prefix, r + 1);
        let sum_l = vec_get(prefix, l);
        let result = sum_r_plus_1 - sum_l;
        let _p = println(result);
        qi = qi + 1
    };

    let _fv = vec_free(v);
    let _fp = vec_free(prefix);
    0
};

